#nullable enable // autogenerated  

using System.Linq;
using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Buffs.Grids;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Seeds;
using MVZ2.Vanilla.Level;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Grids;
using PVZEngine.Level;
using Tools;
using UnityEngine;
using MVZ2.Vanilla.Grids;

namespace MVZ2.GameContent.Stages
{
    [StageDefinition(VanillaStageNames.FeedFeast)]
    public partial class FeedFeast : StageDefinition
    {
        public FeedFeast(string nsp, string name) : base(nsp, name)
        {
            AddBehaviour(new WaveStageBehaviour(this));
            AddBehaviour(new FinalWaveClearBehaviour(this));
            AddBehaviour(new GemStageBehaviour(this));
            AddBehaviour(new StarshardStageBehaviour(this));
            AddBehaviour(new ConveyorStageBehaviour(this));
        }

        public override void OnSetup(LevelEngine level)
        {
            base.OnSetup(level);

            // 在 column 1 的每一行放置灵魂熔炉  
            for (int row = 0; row < 5; row++)
            {
                float x = level.GetEntityColumnX(1);
                float z = level.GetEntityLaneZ(row);
                float y = level.GetGroundY(x, z);
                Vector3 pos = new Vector3(x, y, z);
                level.Spawn(VanillaContraptionID.soulFurnace, pos, null);
            }

            // 禁用除 column 1 以外的所有格子  
            for (int col = 0; col < level.GetMaxColumnCount(); col++)
            {
                if (col == 1 || col == 2) continue; // 跳过灵魂熔炉所在列  
                for (int lane = 0; lane < level.GetMaxLaneCount(); lane++)
                {
                    var grid = level.GetGrid(col, lane);
                    if (grid == null) continue;
                    grid.AddBuff(VanillaBuffID.Grid.goldenGrid);
                }
            }
        }

        public override void OnUpdate(LevelEngine level)
        {
            base.OnUpdate(level);

            // 永久维持禁用：重置所有 goldenGrid buff 的超时计时器  
            for (int col = 0; col < level.GetMaxColumnCount(); col++)
            {
                if (col == 1 || col == 2) continue;
                for (int lane = 0; lane < level.GetMaxLaneCount(); lane++)
                {
                    var grid = level.GetGrid(col, lane);
                    if (grid == null) continue;

                    var buff = grid.GetFirstBuff(VanillaBuffID.Grid.goldenGrid);
                    if (buff != null)
                    {
                        // 当计时器过了 40% 时重置，避免出现半透明的"即将消失"视觉效果  
                        var timer = buff.GetProperty<FrameTimer>(GoldenGridBuff.PROP_TIMEOUT_TIMER);
                        if (timer != null && timer.GetPassedPercentage() > 0.4f)
                        {
                            timer.Reset();
                        }
                    }
                    else
                    {
                        // 如果 buff 被意外移除（如红龙等机制），重新添加  
                        grid.AddBuff(VanillaBuffID.Grid.goldenGrid);
                    }
                }
            }
        }
    }
}